  let segments = [[]], lastX = null, lastY = null;
  const fn = (x) =&gt; {
    if (contSel.startsWith("f(x) = x²")) return x * x;
    if (contSel.includes("1/x")) return Math.abs(x) &lt; 0.01 ? null : 1/x;
    if (contSel.includes("step")) return x &lt; 0 ? -1 : 1;
    if (contSel.includes("floor")) return Math.floor(x);
  };
  for (let x = xMin; x &lt;= xMax; x += 0.02) {
    const y = fn(x);
    if (y === null || y &lt; yMin - 1 || y &gt; yMax + 1) { segments.push([]); continue; }
    if (lastY !== null && Math.abs(y - lastY) &gt; 0.5 && Math.abs(x - lastX) &lt; 0.05) { segments.push([]); }
    segments[segments.length - 1].push({x, y});
    lastX = x; lastY = y;
  }
  for (const seg of segments) {
    if (seg.length &lt; 2) continue;
    const p = seg.map((p, i) =&gt; (i === 0 ? "M " : "L ") + `${px(p.x)},${py(p.y)}`).join(" ");
