Pick an integral. The widget tries a technique on it and shows the answer — and the trick that worked.

viewof intTech = Inputs.select(["substitution: ∫2x cos(x²) dx", "by parts: ∫x e^x dx", "substitution: ∫e^(3x) dx"], {value: "substitution: ∫2x cos(x²) dx", label: "Integral:"})







{
  let result, technique;
  switch(intTech) {
    case "substitution: ∫2x cos(x²) dx": result = "sin(x²) + C"; technique = "Let u = x². Then du = 2x dx, so ∫2x cos(x²) dx = ∫cos(u) du = sin(u) + C."; break;
    case "by parts: ∫x e^x dx": result = "x e^x − e^x + C = (x − 1) e^x + C"; technique = "Let u = x, dv = e^x dx. Then du = dx, v = e^x. ∫u dv = uv − ∫v du = x e^x − ∫e^x dx."; break;
    case "substitution: ∫e^(3x) dx": result = "(1/3) e^(3x) + C"; technique = "Let u = 3x. du = 3 dx, so dx = du/3. ∫e^u (du/3) = (1/3) e^u + C."; break;
  }
  return html`&lt;div style="margin: 1rem 0;"&gt;
    &lt;div style="font-family:monospace; font-size:1.2rem; text-align:center;"&gt;
      ${intTech} = &lt;strong style="color:#c2185b;"&gt;${result}&lt;/strong&gt;
    &lt;/div&gt;
    &lt;div style="margin-top:0.5rem; color:#666; font-style:italic;"&gt;${technique}&lt;/div&gt;
  &lt;/div&gt;`;
}

Touch
Pick two 2D vectors. The widget computes their dot product and the angle between them.

viewof dpAx = Inputs.range([-5, 5], {value: 3, step: 1, label: "a x:"})
viewof dpAy = Inputs.range([-5, 5], {value: 1, step: 1, label: "a y:"})
viewof dpBx = Inputs.range([-5, 5], {value: 1, step: 1, label: "b x:"})
viewof dpBy = Inputs.range([-5, 5], {value: 4, step: 1, label: "b y:"})






























{
  const dot = dpAx * dpBx + dpAy * dpBy;
  const magA = Math.sqrt(dpAx*dpAx + dpAy*dpAy);
  const magB = Math.sqrt(dpBx*dpBx + dpBy*dpBy);
  const cosT = magA * magB === 0 ? 1 : dot / (magA * magB);
  const angle = Math.acos(Math.max(-1, Math.min(1, cosT))) * 180 / Math.PI;
  return html`&lt;div style="margin: 1rem 0;"&gt;
    &lt;div style="text-align:center; font-family:monospace; font-size:1.1rem;"&gt;
      a · b = ${dpAx}·${dpBx} + ${dpAy}·${dpBy} = &lt;strong style="color:#c2185b;"&gt;${dot}&lt;/strong&gt;
    &lt;/div&gt;
    &lt;div style="text-align:center; font-family:monospace; margin-top:0.4rem; color:#1565c0;"&gt;
      a · b = |a| |b| cos θ &nbsp; ⇒ &nbsp; cos θ = ${dot}/(${magA.toFixed(2)}·${magB.toFixed(2)}) = ${cosT.toFixed(3)}
    &lt;/div&gt;
    &lt;div style="text-align:center; font-family:monospace; margin-top:0.4rem; color:#2e7d32; font-weight:bold;"&gt;
      Angle between a and b: ${angle.toFixed(1)}°
    &lt;/div&gt;
  &lt;/div&gt;`;
}






The dot product a \cdot b = |a| |b| \cos \theta — measures alignment. Positive when angle is acute, zero when perpendicular, negative when obtuse.

