Pick a function. The widget shows the function and its derivative on the same plot.

viewof fnSel5 = Inputs.select(["sin x", "cos x", "tan x", "e^x", "ln x"], {value: "sin x", label: "f(x):"})







{
  const W = 720, H = 320, pad = 30;
  const xMin = fnSel5 === "ln x" ? 0.05 : -2 * Math.PI;
  const xMax = fnSel5 === "ln x" ? 6 : 2 * Math.PI;
  const yMin = fnSel5 === "e^x" ? -1 : -3;
  const yMax = fnSel5 === "e^x" ? 8 : 3;
  const px = v =&gt; pad + ((v - xMin) / (xMax - xMin)) * (W - 2 * pad);
  const py = v =&gt; H - pad - ((v - yMin) / (yMax - yMin)) * (H - 2 * pad);
  const svg = d3.create("svg").attr("viewBox", `0 0 ${W} ${H}`).attr("style","width:100%; max-width:760px; background:#fafafa;");
  svg.append("line").attr("x1", pad).attr("x2", W - pad).attr("y1", py(0)).attr("y2", py(0)).attr("stroke","#1f2933");
  if (xMin &lt;= 0 && xMax &gt;= 0) svg.append("line").attr("x1", px(0)).attr("x2", px(0)).attr("y1", pad).attr("y2", H - pad).attr("stroke","#1f2933");
  let f, df, derLabel;
  if (fnSel5 === "sin x") { f = Math.sin; df = Math.cos; derLabel = "f'(x) = cos x"; }
  else if (fnSel5 === "cos x") { f = Math.cos; df = x =&gt; -Math.sin(x); derLabel = "f'(x) = −sin x"; }
  else if (fnSel5 === "tan x") { f = Math.tan; df = x =&gt; 1/(Math.cos(x)*Math.cos(x)); derLabel = "f'(x) = sec² x"; }
  else if (fnSel5 === "e^x") { f = Math.exp; df = Math.exp; derLabel = "f'(x) = e^x  (its own derivative!)"; }
  else { f = Math.log; df = x =&gt; 1/x; derLabel = "f'(x) = 1/x"; }
  const drawCurve = (fn, color) =&gt; {
    let p = "";
    for (let x = xMin; x &lt;= xMax; x += 0.02) {
      const y = fn(x);
      if (!isFinite(y) || y &lt; yMin - 1 || y &gt; yMax + 1) { if (p) svg.append("path").attr("d", p).attr("fill","none").attr("stroke",color).attr("stroke-width",2); p = ""; continue; }
      p += (p ? " L " : "M ") + `${px(x)},${py(y)}`;
    }
    if (p) svg.append("path").attr("d", p).attr("fill","none").attr("stroke",color).attr("stroke-width",2);
  };
  drawCurve(f, "#c2185b");
  drawCurve(df, "#1565c0");
  svg.append("text").attr("x", 12).attr("y", 18).attr("font-size","13").attr("fill","#c2185b").attr("font-weight","bold").text(`f(x) = ${fnSel5}`);
  svg.append("text").attr("x", 12).attr("y", 36).attr("font-size","13").attr("fill","#1565c0").attr("font-weight","bold").text(derLabel);
  return svg.node();
}






The derivatives of trig, exp, and log are themselves familiar functions — and there’s a beautiful constant (e^x is its own derivative).

