{
  const factorial = n =&gt; n &lt;= 1 ? 1 : n * factorial(n - 1);
  const choose = (n, r) =&gt; factorial(n) / (factorial(r) * factorial(n - r));
  const coeffs = [];
  for (let r = 0; r &lt;= nBin; r++) coeffs.push(choose(nBin, r));
  // Build expansion text
  const term = (r) =&gt; {
    const c = coeffs[r];
    const aPow = nBin - r, bPow = r;
    let aStr = aPow === 0 ? "" : (aPow === 1 ? "a" : `a&lt;sup&gt;${aPow}&lt;/sup&gt;`);
    let bStr = bPow === 0 ? "" : (bPow === 1 ? "b" : `b&lt;sup&gt;${bPow}&lt;/sup&gt;`);
    let coeffStr = c === 1 && (aPow &gt; 0 || bPow &gt; 0) ? "" : c;
    return `${coeffStr}${aStr}${bStr}`;
  };
  const expansion = coeffs.map((_, r) =&gt; term(r)).filter(Boolean).join(" + ");
  // Build Pascal's triangle (rows 0 .. nBin)
  let triangle = "";
  for (let row = 0; row &lt;= nBin; row++) {
    const rowCoeffs = [];
    for (let r = 0; r &lt;= row; r++) rowCoeffs.push(choose(row, r));
    triangle += `&lt;div style="text-align:center; font-family:monospace; ${row === nBin ? 'color:#c2185b; font-weight:bold;' : 'color:#666;'}"&gt;${rowCoeffs.join(' ')}&lt;/div&gt;`;
  }
  return html`&lt;div style="margin: 1rem 0;"&gt;
    &lt;div style="text-align:center; font-family:monospace; font-size:1.2rem; padding: 0.5rem;"&gt;
      (a + b)&lt;sup&gt;${nBin}&lt;/sup&gt; = &lt;span style="color:#c2185b; font-weight:bold;"&gt;${expansion}&lt;/span&gt;
    &lt;/div&gt;
    &lt;details style="margin: 1rem auto; max-width: 320px;"&gt;&lt;summary style="text-align:center; cursor:pointer;"&gt;Pascal's triangle (rows 0–${nBin})&lt;/summary&gt;
      ${triangle}
    &lt;/details&gt;
  &lt;/div&gt;`;
}






The coefficients of (a + b)^n are exactly the n-th row of Pascal’s triangle — and they are exactly the binomial coefficients \binom{n}{r}.

