    ["cos(2θ)", Math.cos(2*t), c*c - s*s],
  ];
  return html`&lt;div style="margin: 1rem 0;"&gt;
    &lt;table style="margin: 0 auto; border-collapse:collapse; font-family:monospace;"&gt;
      &lt;tr&gt;&lt;th style="padding: 6px 14px;"&gt;LHS&lt;/th&gt;&lt;th style="padding: 6px 14px;"&gt;value&lt;/th&gt;&lt;th style="padding: 6px 14px;"&gt;RHS&lt;/th&gt;&lt;/tr&gt;
      ${checks.map(([nm, l, r]) =&gt; `&lt;tr style="border-top:1px solid #ccc;"&gt;&lt;td style="padding: 4px 14px;"&gt;${nm}&lt;/td&gt;&lt;td style="padding: 4px 14px;"&gt;${l.toFixed(4)} ≈ ${r.toFixed(4)}&lt;/td&gt;&lt;td style="padding: 4px 14px; color:#666;"&gt;${
        nm === 'sin²θ + cos²θ' ? '1'
        : nm === '1 + tan²θ' ? 'sec²θ'
        : nm === 'sin(2θ)' ? '2 sin θ cos θ'
        : 'cos²θ − sin²θ'
      }&lt;/td&gt;&lt;/tr&gt;`).join('')}
    &lt;/table&gt;
  &lt;/div&gt;`;
}






Identities are equalities true for every \theta. Move the slider — LHS and RHS always agree. Identities are the algebraic side of trigonometry.

